import{_ as e,o as i,c as n,Q as t}from"./chunks/framework.7ed72bc6.js";const f=JSON.parse('{"title":"Lightning 2.x July Release","description":"The July release of Lightning is now available, bringing enhancements, bug fixes, and new features across all main components, including Lightning Core v2.11.0, Lightning SDK v5.4.0, and Lightning CLI v2.12.0.","frontmatter":{"layout":"blog","title":"Lightning 2.x July Release","description":"The July release of Lightning is now available, bringing enhancements, bug fixes, and new features across all main components, including Lightning Core v2.11.0, Lightning SDK v5.4.0, and Lightning CLI v2.12.0.","date":"2023-7-31"},"headers":[],"relativePath":"blogs/releaseJuly2023.md","filePath":"blogs/releaseJuly2023.md"}'),r={name:"blogs/releaseJuly2023.md"},a=t('<p>Dear Lightning community,</p><p>We are excited to announce the summer release of Lightning! As part of our ongoing quarterly release schedule, we&#39;ve named this the &#39;July Release&#39;. As always, we&#39;re thrilled to bring to you a host of enhancements, bug fixes, and new features, all of which we&#39;re sure will enhance your Lightning experience.</p><p>We hope you&#39;re enjoying a fantastic summer. This release is packed with updates designed to improve your experience with Lightning. We&#39;ve been hard at work incorporating your feedback, optimizing our offerings, and developing new features. However, due to the summer schedule, a few items had to be deferred to the October release. We apologize for any inconvenience this may cause and appreciate your understanding.</p><p>Please take the time to explore the latest versions of our key components:</p><ul><li>Lightning Core <a href="https://github.com/rdkcentral/Lightning" target="_blank" rel="noreferrer">v2.11.0</a></li><li>Lightning SDK <a href="https://github.com/rdkcentral/Lightning-SDK" target="_blank" rel="noreferrer">v5.4.0</a></li><li>Lightning CLI <a href="https://github.com/rdkcentral/Lightning-CLI" target="_blank" rel="noreferrer">v2.12.0</a></li></ul><h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="lightning-core" tabindex="-1">Lightning Core <a class="header-anchor" href="#lightning-core" aria-label="Permalink to &quot;Lightning Core&quot;">​</a></h2><ul><li>Updated typings of Element so <code>flexItem</code> can be <code>false</code>.</li><li>Fixed an issue with applying vertex-specific color to the hole punch fragment.</li><li>Fixed a regression related to TextTextureRenderer word wrapping. <a href="https://github.com/rdkcentral/Lightning/issues/488" target="_blank" rel="noreferrer">#488</a></li><li>Fixed alpha channel detection when using in-process image handling. <a href="https://github.com/rdkcentral/Lightning/issues/493" target="_blank" rel="noreferrer">#493</a></li><li>Fixed a typo referencing the <code>renderOffscreen</code> method of <code>Element</code>.</li><li>Added <code>webgl2</code> as the fallback context option if <code>webgl</code> or <code>experimental-webgl</code> is unavailable. <a href="https://github.com/rdkcentral/Lightning/issues/496" target="_blank" rel="noreferrer">#496</a></li><li>Added event bubbling support for pointer events. <a href="https://github.com/rdkcentral/Lightning/issues/485" target="_blank" rel="noreferrer">#485</a></li><li>Added support for getting local coordinates with pointer events. <a href="https://github.com/rdkcentral/Lightning/issues/484" target="_blank" rel="noreferrer">#484</a></li></ul><h2 id="lightning-sdk" tabindex="-1">Lightning SDK <a class="header-anchor" href="#lightning-sdk" aria-label="Permalink to &quot;Lightning SDK&quot;">​</a></h2><ul><li>Fixed an issue with applying vertex-specific color to the hole punch fragment.</li><li>Added support for cleanup of event listeners and targets to prevent retaining memory during app lifetime.</li><li>Added support to kill previously keepAlive page instance.</li></ul><h2 id="lightning-cli" tabindex="-1">Lightning CLI <a class="header-anchor" href="#lightning-cli" aria-label="Permalink to &quot;Lightning CLI&quot;">​</a></h2><ul><li>Fixed issue with rollup typescript project throwing error when accessing process env. <a href="https://github.com/rdkcentral/Lightning-CLI/issues/235" target="_blank" rel="noreferrer">#235</a></li><li>Added &quot;include&quot; config in tsconfig.json for <code>lng create</code> command.</li><li>Added support for getting &quot;esEnv&quot; from settings.json file for <code>lng dist</code>. <a href="https://github.com/rdkcentral/Lightning-CLI/issues/224" target="_blank" rel="noreferrer">#224</a></li><li>Added support for transpiling .mjs files to ES5 with rollup.</li><li>Fixed the issue related to Babel ignore not possible to use in a babel.config.json. <a href="https://github.com/rdkcentral/Lightning-CLI/issues/177" target="_blank" rel="noreferrer">#117</a></li></ul>',12),o=[a];function l(s,g,h,c,d,u){return i(),n("div",null,o)}const m=e(r,[["render",l]]);export{f as __pageData,m as default};
